import { useEffect, useState } from "react"
import API from "../api/axios"
import { useParams } from "react-router-dom"

export default function RestaurantDetails() {
  const { id } = useParams()
  const [restaurant, setRestaurant] = useState({})
  const [reviews, setReviews] = useState([])

  useEffect(() => {
    API.get(`/restaurants/${id}`).then(res => setRestaurant(res.data))
    API.get(`/restaurants/${id}/reviews`).then(res => setReviews(res.data))
  }, [id])

  return (
    <div className="p-6">
      <img
        src={restaurant.photos?.[0] || "https://via.placeholder.com/600"}
        className="w-full h-64 object-cover rounded"
      />

      <h1 className="text-2xl font-bold mt-4">{restaurant.name}</h1>
      <p className="text-gray-600">{restaurant.description}</p>
      <p className="text-yellow-500 text-lg mt-2">
        {"⭐".repeat(Math.round(restaurant.avg_rating || 0))}
      </p>

      <h2 className="text-xl mt-6 mb-2">Reviews</h2>

      {reviews.map(r => (
        <div key={r.review_id} className="bg-white p-4 mb-3 rounded shadow">
          <p className="text-yellow-500">{"⭐".repeat(r.rating)}</p>
          <p>{r.comment}</p>
        </div>
      ))}
    </div>
  )
}
